public class FlatMap {
    static int[] flatten(int[][] matrix) {
        int total = 0;
        for (int[] row : matrix) total += row.length;
        int[] result = new int[total];
        int idx = 0;
        for (int[] row : matrix) {
            for (int v : row) result[idx++] = v;
        }
        return result;
    }
    public static void main(String[] args) {
        int[][] m = {{1,2},{3},{4,5,6}};
        int[] flat = flatten(m);
        System.out.println(flat.length);
        System.out.println(flat[0] + flat[flat.length-1]);
    }
}
